// File: /home/ty/Repositories/ai_workspace/helen-keller-activation/src/index.ts

import { LMStudioClient } from "@lmstudio/sdk";
import * as fs from 'fs';

class HelenKellerActivationNetwork {
  private network: Map<string, ActivationNode> = new Map();
  private lmStudio: LMStudioClient;
  private models: any = {};

  async initialize() {
    this.lmStudio = new LMStudioClient({
      baseUrl: "http://localhost:1234/v1" // LM Studio local server
    });

    // Load ALL models locally - zero API costs
    console.log("Loading local models...");
    this.models = {
      fast: await this.lmStudio.llm.load("bartowski/Qwen2.5-3B-Instruct-GGUF"),
      reason: await this.lmStudio.llm.load("bartowski/DeepSeek-R1-Distill-Qwen-7B-GGUF"),  
      embed: await this.lmStudio.llm.load("nomic-ai/nomic-embed-text-v1.5-GGUF")
    };
  }

  async think(input: string) {
    // 1. Convert input to activation pattern
    const embedding = await this.models.embed.embed(input);

    // 2. Activate resonant nodes
    const activated = this.activateResonantNodes(embedding);

    // 3. Let activation cascade through network
    const thoughtPath = this.propagateActivation(activated);

    // 4. Generate output from activation pattern
    const pattern = this.extractPattern(thoughtPath);

    // 5. Use appropriate model based on pattern coherence
    if (pattern.coherence > 0.7) {
      // System 1: Fast, intuitive
      return await this.models.fast.respond(pattern.narrative);
    } else {
      // System 2: Slow, deliberative
      return await this.models.reason.respond(pattern.narrative);
    }
  }

  learn(experience: string) {
    // Learning = strengthening activated pathways
    const path = this.think(experience);
    this.strengthenPath(path);
    // No database write - the network IS the memory
  }
}

// Usage - completely self-contained
const helen = new HelenKellerActivationNetwork();
await helen.initialize();
await helen.learn("Water is wet and cold");
const response = await helen.think("What is water like?");
// The memory of "wet and cold" emerges from activation patterns!
```

